 1	import React, { FC } from 'react';
 2	
 3	import CreateProjectModal from '@kubevirt-utils/components/CreateProjectModal/CreateProjectModal';
 4	import { useQueryParamsMethods } from '@kubevirt-utils/components/ListPageFilter/hooks/useQueryParamsMethods';
 5	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { getName } from '@kubevirt-utils/resources/shared';
 8	import { useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 9	import { Button, ButtonVariant } from '@patternfly/react-core';
10	import { PlusCircleIcon } from '@patternfly/react-icons';
11	import { TEXT_FILTER_LABELS_ID } from '@virtualmachines/list/hooks/constants';
12	
13	const CreateProject: FC = () => {
14	  const { t } = useKubevirtTranslation();
15	  const [_, setActiveNamespace] = useActiveNamespace();
16	  const { removeQueryArguments } = useQueryParamsMethods();
17	  const { createModal } = useModal();
18	  return (
19	    <Button
20	      onClick={() =>
21	        createModal((props) => (
22	          <CreateProjectModal
23	            {...props}
24	            createdProject={(namespace) => {
25	              removeQueryArguments(TEXT_FILTER_LABELS_ID);
26	              setActiveNamespace(getName(namespace));
27	            }}
28	          />
29	        ))
30	      }
31	      className="vms-tree-view__action"
32	      icon={<PlusCircleIcon />}
33	      iconPosition="start"
34	      variant={ButtonVariant.link}
35	    >
36	      {t('Create Project')}
37	    </Button>
38	  );
39	};
40	
41	export default CreateProject;

